import { connectServer } from './connect.js';
import { initialize } from './initialize.js';
import { createSearchTool } from './search.js';
import { createTools } from './tools/index.js';

async function main() {
  const server = initialize();

  const existingTools = new Set<string>();
  await createSearchTool(server);
  await createTools(server, existingTools);
  await connectServer(server);
}

main().catch((error) => {
  console.error('Fatal error in trying to initialize MCP server: ', error);
  process.exit(1);
});
